package main

import "fmt"

func main() {
    // ---- Creating slices ----
    var s1 []int
    s2 := []int{1, 2, 3, 4, 5}
    s3 := make([]int, 3)  // length 3, capacity 3
    s4 := make([]int, 3, 5)  // length 3, capacity 5

    fmt.Println("s1:", s1)
    fmt.Println("s2:", s2)
    fmt.Println("s3:", s3)
    fmt.Println("s4:", s4)

    // ---- Slicing an array ----
    arr := [5]int{10, 20, 30, 40, 50}
    slice := arr[1:4]  // [20, 30, 40]
    fmt.Println("Slice from array:", slice)

    // ---- Slice operations ----
    s := []int{1, 2, 3}

    // Append
    s = append(s, 4)
    s = append(s, 5, 6)
    fmt.Println("After append:", s)

    // Copy
    copySlice := make([]int, len(s))
    copy(copySlice, s)
    fmt.Println("Copy:", copySlice)

    // ---- Slice length and capacity ----
    nums := []int{10, 20, 30, 40, 50}
    fmt.Println("Length:", len(nums))
    fmt.Println("Capacity:", cap(nums))

    // ---- Sub-slice ----
    sub := nums[1:3]
    fmt.Println("Sub-slice:", sub)
    fmt.Println("Sub length:", len(sub))
    fmt.Println("Sub capacity:", cap(sub))

    // ---- Modifying slice modifies original ----
    original := []int{1, 2, 3, 4, 5}
    copy2 := original[1:4]
    copy2[0] = 99
    fmt.Println("Original after modification:", original)

    // ---- Nil slices ----
    var nilSlice []int
    emptySlice := []int{}

    fmt.Println("nilSlice == nil:", nilSlice == nil)
    fmt.Println("emptySlice == nil:", emptySlice == nil)

    // ---- Slice of strings ----
    items := []string{"Sword", "Shield", "Potion"}
    items = append(items, "Key")
    for _, item := range items {
        fmt.Println("Item:", item)
    }
}

